#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    cin >> n;
    vector<pair<int,int>> iv(n);
    for (auto& [l, r] : iv) cin >> l >> r;

    // Sort by start time
    sort(iv.begin(), iv.end());

    // min-heap of end times of active rooms
    priority_queue<int, vector<int>, greater<int>> pq;

    for (auto& [l, r] : iv) {
        if (!pq.empty() && pq.top() <= l) {
            pq.pop();  // reuse the room that freed up earliest
        }
        pq.push(r);   // assign this interval to a room ending at r
    }

    cout << pq.size() << "\n";  // rooms still occupied = total needed
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
// Jobs have processing time p[i] and weight w[i].
// Minimize sum of w[i] * C[i] where C[i] = completion time of job i.
// Exchange argument: schedule job i before j iff w[i]/p[i] > w[j]/p[j]
// i.e., w[i]*p[j] > w[j]*p[i]  (avoid floating point: cross-multiply)

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    cin >> n;
    vector<pair<int,int>> jobs(n); // {processing_time, weight}
    for (auto& [p, w] : jobs) cin >> p >> w;

    // Sort by decreasing ratio w/p  =>  w[i]*p[j] > w[j]*p[i]
    sort(jobs.begin(), jobs.end(), [](auto& a, auto& b) {
        return (long long)a.second * b.first > (long long)b.second * a.first;
    });

    long long total_cost = 0, time = 0;
    for (auto& [p, w] : jobs) {
        time += p;
        total_cost += (long long)w * time;
    }

    cout << total_cost << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
// Cost to connect two ropes = sum of their lengths.
// Minimize total cost of connecting all ropes into one.
// Greedy: always merge the two shortest ropes first.

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    cin >> n;
    priority_queue<long long, vector<long long>, greater<long long>> pq;
    for (int i = 0; i < n; i++) {
        long long x; cin >> x;
        pq.push(x);
    }

    long long total = 0;
    while (pq.size() > 1) {
        long long a = pq.top(); pq.pop();
        long long b = pq.top(); pq.pop();
        total += a + b;
        pq.push(a + b);
    }

    cout << total << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
// Given array a[], flip sign of any element, exactly k times.
// Maximize the sum.

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, k;
    cin >> n >> k;
    vector<int> a(n);
    for (auto& x : a) cin >> x;

    sort(a.begin(), a.end()); // sort ascending

    // Step 1: flip negatives from most negative first
    for (int i = 0; i < n && k > 0 && a[i] < 0; i++, k--)
        a[i] = -a[i];

    // Step 2: if k is still odd, flip the minimum element
    if (k % 2 == 1) {
        sort(a.begin(), a.end());
        a[0] = -a[0];
    }

    cout << accumulate(a.begin(), a.end(), 0LL) << "\n";
    return 0;
}

