#include <bits/stdc++.h>
using namespace std;
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n; cin >> n;
    vector<pair<int,int>> tasks(n); // {deadline, processing_time}
    for (auto& [d, t] : tasks) cin >> t >> d;

    // EDF: sort by deadline
    sort(tasks.begin(), tasks.end());

    long long time = 0, max_late = 0;
    for (auto& [d, t] : tasks) {
        time += t;
        max_late = max(max_late, time - d);
    }
    // Lateness is max(0, ...) but time-d can be negative, so:
    cout << max(0LL, max_late) << "\n";
    return 0;
}

