#include <bits/stdc++.h>
using namespace std;
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n; cin >> n;
    vector<pair<int,int>> b(n);
    for (auto& [l, r] : b) cin >> l >> r;

    sort(b.begin(), b.end(), [](auto& a, auto& b_) {
        return a.second < b_.second;
    });

    int arrows = 0;
    int arrow_pos = INT_MIN;

    for (auto& [l, r] : b) {
        if (l > arrow_pos) {       // current arrow doesn't reach this balloon
            arrows++;
            arrow_pos = r;         // shoot arrow at the right end
        }
    }

    cout << arrows << "\n";
    return 0;
}

