#include <bits/stdc++.h>
using namespace std;
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n, m;
    cin >> n >> m;
    vector<int> a(n), b(m);
    for (auto& x : a) cin >> x;
    for (auto& x : b) cin >> x;

    sort(a.begin(), a.end());
    sort(b.begin(), b.end());

    int i = 0, j = 0, ans = 0;
    while (i < n && j < m) {
        if (b[j] >= a[i]) {
            ans++;   // satisfy child i with pack j
            i++; j++;
        } else {
            j++;     // pack too small, try next pack
        }
    }

    cout << ans << "\n";
    return 0;
}
